// GA4 × Google広告 連携チェックリスト
const setupChecklist = {
  googleSignals: {
    label: 'Googleシグナル有効化',
    status: true,
    action: 'GA4管理 → プロパティ設定 → Googleシグナルのデータ収集'
  },
  googleAdsLink: {
    label: 'Google広告アカウントのリンク',
    status: false,
    action: 'GA4管理 → プロダクトのリンク設定 → Google広告のリンク'
  },
  conversionImport: {
    label: 'コンバージョンのGoogle広告へのインポート',
    status: false,
    action: 'Google広告管理 → ツール → コンバージョン → GAからインポート'
  },
  privacyPolicy: {
    label: 'プライバシーポリシーへの記載',
    status: true,
    action: 'プライバシーポリシーページにGoogleシグナルの利用を明記'
  },
  demographicsReport: {
    label: 'デモグラフィクスレポートの有効化',
    status: true,
    action: 'GA4管理 → プロパティ設定 → レポートのID'
  }
};

function getIncompleteItems(checklist) {
  const incomplete = Object.values(checklist).filter(item => !item.status);

  if (incomplete.length === 0) {
    return '全項目の設定が完了しています。';
  }

  return incomplete
    .map(item => `未設定: ${item.label}\n対応: ${item.action}`)
    .join('\n\n');
}

console.log(getIncompleteItems(setupChecklist));
// 出力:
// 未設定: Google広告アカウントのリンク
// 対応: GA4管理 → プロダクトのリンク設定 → Google広告のリンク
//
// 未設定: コンバージョンのGoogle広告へのインポート
// 対応: Google広告管理 → ツール → コンバージョン → GAからインポート
